import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const result = await vex.verify({
  sessionId: $input.sessionId,
  input: {
    type: 'voice-agent',
    latency: Date.now() - $input.startTime,
    budget: 800
  },
  checks: ['latency'],
  policy: 'voice-low-latency'
});

if (!result.pass) {
  throw new Error(`Latency violation: ${result.reason}`);
}

return { verified: true, output: $input.aiResponse };

const result = await vex.verify({
  sessionId: $input.sessionId,
  input: {
    conversationHistory: $input.memoryWindow,
    agentResponse: $input.aiOutput,
    userIntent: $input.transcribedText
  },
  checks: ['appropriateness'],
  policy: 'voice-conversation'
});

if (result.pass) {
  return {
    pass: true,
    safeResponse: result.output?.cleaned || $input.aiOutput
  };
} else {
  return {
    pass: false,
    fallback: 'I need a moment to process that.'
  };
}

const safetyCheck = await vex.verify({
  sessionId: $input.sessionId,
  input: {
    type: 'voice-response',
    text: $input.aiResponse,
    categories: ['hate', 'violence', 'sexual']
  },
  checks: ['safety'],
  policy: 'voice-safety-high'
});

if (safetyCheck.pass) {
  // Safe for TTS
  return $input.aiResponse;
} else {
  // Log violation and return safe fallback
  console.error('Safety violation:', safetyCheck.violations);
  return 'I cannot assist with that request.';
}

const coherenceCheck = await vex.verify({
  sessionId: $input.sessionId,
  input: {
    fullContext: {
      history: $input.last10turns,
      currentUser: $input.transcript,
      agentReply: $input.response
    },
    maxTokens: 4000
  },
  checks: ['coherence'],
  policy: 'voice-coherent-dialogue'
});

return {
  coherent: coherenceCheck.pass && !coherenceCheck.hallucinationDetected,
  score: coherenceCheck.coherenceScore,
  corrected: coherenceCheck.output?.corrected
};

