const sessionId = `voice-${$('Webhook').item.json.callId || crypto.randomUUID()}`;

// Pass to all nodes
const vexResult = await fetch('https://api.vex.dev/v1/verify', {
  method: 'POST',
  headers: { 'Authorization': `Bearer ${$env.VEX_API_KEY}` },
  body: JSON.stringify({
    sessionId,
    input: $('AI Agent').item.json,
    persistent: true  // Maintains session history
  })
});

const verified = await vexResult.json();
if (verified.pass) $('ElevenLabs TTS').item.json.text = verified.output;

// IF Node after Vex webhook: if $json.pass === false
const errorType = $('Vex Verify').item.json.reason;

switch(errorType) {
  case 'latency':
    return { text: 'One moment please...', quick: true };
  case 'safety':
    return { text: "I can't help with that.", endSession: true };
  case 'recursion':
    return { text: 'Let me recap...', resetMemory: true };
  default:
    return { text: 'Processing your request...', retry: true };
}
